-- Atualiza total_amount dos pedidos
UPDATE sales.orders o SET total_amount = sub.total
FROM (
  SELECT order_id, SUM(total_price) AS total
  FROM sales.order_items
  GROUP BY order_id
) sub
WHERE o.id = sub.order_id;